SELECT data_id, station_id, visibility, wind_speed, data_quality_flag
FROM weather_data
WHERE relative_humidity > 70 AND wind_speed < 10;

SELECT DISTINCT regions.region_name, weather_station_region.station_id
FROM regions
JOIN weather_station_region ON regions.region_id = weather_station_region.region_id;

SELECT date_time, 'Visibility' AS param_name
FROM weather_data
WHERE wind_speed > 15;
